      { id: "ge_text_4", german: "Leinen", english: "Linen", difficulty: "easy", example: "Linen is lightweight breathable fabric perfect for summer clothing keeping you cool in hot weather", exampleTranslation: "Leinen ist leichter atmungsaktiver Stoff perfekt für Sommerkleidung hält Sie kühl bei heißem Wetter" },
      { id: "ge_text_5", german: "Polyester", english: "Polyester", difficulty: "easy", example: "Polyester is synthetic durable fabric resisting wrinkles and shrinking making it practical for everyday wear", exampleTranslation: "Polyester ist synthetischer haltbarer Stoff widersteht Falten und Schrumpfen macht es praktisch für alltägliches Tragen" },
      { id: "ge_text_6", german: "Textil", english: "Textile", difficulty: "easy", example: "Textiles encompass all fabric materials used for clothing home furnishings and industrial applications widely", exampleTranslation: "Textilien umfassen alle Stoffmaterialien verwendet für Kleidung Heimtextilien und industrielle Anwendungen weit verbreitet" },
      { id: "ge_text_7", german: "Muster", english: "Pattern", difficulty: "medium", example: "Fabric patterns include stripes florals and geometric designs adding visual interest and style to textiles", exampleTranslation: "Stoffmuster beinhalten Streifen Blumenmuster und geometrische Designs fügen visuelles Interesse und Stil zu Textilien hinzu" },
      { id: "ge_text_8", german: "Färben", english: "To dye", difficulty: "medium", example: "Dyeing fabrics changes colors creating vibrant hues and patterns through chemical or natural coloring processes", exampleTranslation: "Stoffe zu färben ändert Farben schafft lebendige Farbtöne und Muster durch chemische oder natürliche Färbeprozesse" },
      { id: "ge_text_9", german: "Gewebe", english: "Weave", difficulty: "medium", example: "Fabric weave patterns affect texture strength and appearance created by interlacing threads systematically", exampleTranslation: "Stoffwebmuster beeinflussen Textur Stärke und Aussehen geschaffen durch systematisches Verflechten von Fäden" },
      { id: "ge_text_10", german: "Qualität", english: "Quality", difficulty: "medium", example: "Fabric quality determines durability comfort and longevity affecting how clothing looks and feels over time", exampleTranslation: "Stoffqualität bestimmt Haltbarkeit Komfort und Langlebigkeit beeinflusst wie Kleidung im Laufe der Zeit aussieht und sich anfühlt" },
      { id: "ge_text_11", german: "Synthetik", english: "Synthetic", difficulty: "medium", example: "Synthetic fabrics are man-made materials offering durability easy care and various performance characteristics", exampleTranslation: "Synthetische Stoffe sind künstliche Materialien bieten Haltbarkeit einfache Pflege und verschiedene Leistungscharakteristiken" },
      { id: "ge_text_12", german: "Naturfaser", english: "Natural fiber", difficulty: "medium", example: "Natural fibers from plants and animals are biodegradable comfortable and environmentally friendly textile options", exampleTranslation: "Naturfasern von Pflanzen und Tieren sind biologisch abbaubar komfortabel und umweltfreundliche Textiloptionen" },
      { id: "ge_text_13", german: "Welcher Stoff ist das?", english: "What fabric is this?", difficulty: "hard", example: "What fabric is this made from? It feels incredibly soft and luxurious against the skin!", exampleTranslation: "Welcher Stoff ist das? Es fühlt sich unglaublich weich und luxuriös auf der Haut an!" },
      { id: "ge_text_14", german: "Stoffeigenschaften", english: "Fabric properties", difficulty: "hard", example: "Fabric properties including breathability durability and drape determine suitability for different clothing applications!", exampleTranslation: "Stoffeigenschaften einschließlich Atmungsaktivität Haltbarkeit und Fall bestimmen Eignung für verschiedene Kleidungsanwendungen!" },
      { id: "ge_text_15", german: "Textilpflege", english: "Textile care", difficulty: "hard", example: "Proper textile care following washing drying and storage instructions extends clothing life maintaining quality and appearance!", exampleTranslation: "Richtige Textilpflege folgend Wasch- Trocknungs- und Lagerungsanweisungen verlängert Kleidungsleben erhält Qualität und Aussehen!" }
