      { id: "ge_weather2_6", german: "Wolke", english: "Cloud", difficulty: "easy", example: "Clouds form from water vapor creating different shapes and patterns indicating upcoming weather changes", exampleTranslation: "Wolken bilden sich aus Wasserdampf schaffen verschiedene Formen und Muster zeigen kommende Wetterveränderungen an" },
      { id: "ge_weather2_7", german: "Gewitter", english: "Thunderstorm", difficulty: "medium", example: "Thunderstorms bring heavy rain lightning and thunder requiring caution and shelter for safety during storms", exampleTranslation: "Gewitter bringen starken Regen Blitz und Donner erfordern Vorsicht und Schutz für Sicherheit während Stürmen" },
      { id: "ge_weather2_8", german: "Nebel", english: "Fog", difficulty: "medium", example: "Fog reduces visibility creating mysterious atmospheric conditions requiring careful driving and navigation through it", exampleTranslation: "Nebel reduziert Sichtbarkeit schafft mysteriöse atmosphärische Bedingungen erfordert vorsichtiges Fahren und Navigation dadurch" },
      { id: "ge_weather2_9", german: "Frost", english: "Frost", difficulty: "medium", example: "Frost forms when temperatures drop below freezing creating icy crystals on surfaces overnight beautifully", exampleTranslation: "Frost bildet sich wenn Temperaturen unter den Gefrierpunkt fallen schafft wunderschön eisige Kristalle auf Oberflächen über Nacht" },
      { id: "ge_weather2_10", german: "Wettervorhersage", english: "Weather forecast", difficulty: "medium", example: "Weather forecasts predict upcoming conditions helping people plan activities and prepare for changing weather", exampleTranslation: "Wettervorhersagen prognostizieren kommende Bedingungen helfen Menschen Aktivitäten zu planen und sich auf wechselndes Wetter vorzubereiten" },
      { id: "ge_weather2_11", german: "Klimawandel", english: "Climate change", difficulty: "medium", example: "Climate change affects global weather patterns requiring urgent action to reduce emissions and protect environment", exampleTranslation: "Klimawandel beeinflusst globale Wettermuster erfordert dringende Handlungen um Emissionen zu reduzieren und Umwelt zu schützen" },
      { id: "ge_weather2_12", german: "Luftfeuchtigkeit", english: "Humidity", difficulty: "medium", example: "Humidity measures moisture in air affecting comfort how hot or cold temperatures actually feel", exampleTranslation: "Luftfeuchtigkeit misst Feuchtigkeit in der Luft beeinflusst Komfort wie heiß oder kalt sich Temperaturen tatsächlich anfühlen" },
      { id: "ge_weather2_13", german: "Wie ist das Wetter?", english: "What's the weather like?", difficulty: "hard", example: "What's the weather like today? Should I bring an umbrella or wear a jacket outside?", exampleTranslation: "Wie ist das Wetter heute? Sollte ich einen Regenschirm mitbringen oder eine Jacke draußen tragen?" },
      { id: "ge_weather2_14", german: "Wetterbedingungen", english: "Weather conditions", difficulty: "hard", example: "Weather conditions vary dramatically across regions seasons affecting agriculture transportation and daily life significantly!", exampleTranslation: "Wetterbedingungen variieren dramatisch über Regionen und Jahreszeiten beeinflussen erheblich Landwirtschaft Transport und tägliches Leben!" },
      { id: "ge_weather2_15", german: "Klimatische Veränderungen", english: "Climatic changes", difficulty: "hard", example: "Climatic changes impact ecosystems agriculture and human societies requiring adaptation and environmental protection efforts globally!", exampleTranslation: "Klimatische Veränderungen beeinflussen Ökosysteme Landwirtschaft und menschliche Gesellschaften erfordern global Anpassung und Umweltschutzbemühungen!" }
